// breakpoints/contribution.ts
import { Contribution, ContributionType } from 'vscode';
import { Breakpoint } from 'vscode-debugadapter';

export function addTriggeredBreakpoint(
  contribution: Contribution,
  breakpoint: Breakpoint,
  triggerBreakpoints: Breakpoint[]
): void {
  const triggeredBreakpoint = contribution.createConfiguration(
    'addTriggeredBreakpoint',
    ContributionType.Command
  );

  const defaultTriggerBreakpoint = triggerBreakpoints.length > 0 ? triggerBreakpoints[0] : null;

  triggeredBreakpoint
    .registerCommand(
      'workbench.action.addTriggeredBreakpoint',
      () => {
        const triggerBreakpoint = triggerBreakpoints.find((bp) => bp.id === defaultTriggerBreakpoint?.id);
        if (triggerBreakpoint) {
          // Set the default trigger breakpoint
          vscode.commands.executeCommand('workbench.action.setTriggeredBreakpoint', triggerBreakpoint);
        }
      }
    )
    .registerOption(
      'defaultTriggerBreakpoint',
      {
        type: 'string',
        default: defaultTriggerBreakpoint?.id,
      },
      (value) => {
        const triggerBreakpoint = triggerBreakpoints.find((bp) => bp.id === value);
        if (triggerBreakpoint) {
          // Set the default trigger breakpoint
          vscode.commands.executeCommand('workbench.action.setTriggeredBreakpoint', triggerBreakpoint);
        }
      }
    );
}
```

